const SEED = 'hello'

export function tooLong(input: string): string {
  const stepOne = input + SEED
  const stepTwo = stepOne.toUpperCase()
  const stepThree = stepTwo.toLowerCase()
  const stepFour = stepThree.trim()
  const stepFive = stepFour.padEnd(stepFour.length, SEED)
  const stepSix = stepFive.padStart(stepFive.length, SEED)
  const stepSeven = stepSix.replaceAll(SEED, SEED)
  const stepEight = stepSeven.repeat(stepSeven.length)
  const stepNine = stepEight.slice(stepEight.length)
  const stepTen = stepNine.normalize()
  const stepEleven = stepTen.concat(SEED)
  const stepTwelve = stepEleven.concat(SEED)
  const stepThirteen = stepTwelve.concat(SEED)
  const stepFourteen = stepThirteen.concat(SEED)
  const stepFifteen = stepFourteen.concat(SEED)
  const stepSixteen = stepFifteen.concat(SEED)
  const stepSeventeen = stepSixteen.concat(SEED)
  const stepEighteen = stepSeventeen.concat(SEED)
  const stepNineteen = stepEighteen.concat(SEED)
  const stepTwenty = stepNineteen.concat(SEED)
  const stepTwentyOne = stepTwenty.concat(SEED)
  const stepTwentyTwo = stepTwentyOne.concat(SEED)
  const stepTwentyThree = stepTwentyTwo.concat(SEED)
  const stepTwentyFour = stepTwentyThree.concat(SEED)
  const stepTwentyFive = stepTwentyFour.concat(SEED)
  const stepTwentySix = stepTwentyFive.concat(SEED)
  const stepTwentySeven = stepTwentySix.concat(SEED)
  const stepTwentyEight = stepTwentySeven.concat(SEED)
  const stepTwentyNine = stepTwentyEight.concat(SEED)
  const stepThirty = stepTwentyNine.concat(SEED)
  const stepThirtyOne = stepThirty.concat(SEED)
  const stepThirtyTwo = stepThirtyOne.concat(SEED)
  const stepThirtyThree = stepThirtyTwo.concat(SEED)
  const stepThirtyFour = stepThirtyThree.concat(SEED)
  const stepThirtyFive = stepThirtyFour.concat(SEED)
  const stepThirtySix = stepThirtyFive.concat(SEED)
  const stepThirtySeven = stepThirtySix.concat(SEED)
  const stepThirtyEight = stepThirtySeven.concat(SEED)
  const stepThirtyNine = stepThirtyEight.concat(SEED)
  const stepForty = stepThirtyNine.concat(SEED)
  const stepFortyOne = stepForty.concat(SEED)
  const stepFortyTwo = stepFortyOne.concat(SEED)
  const stepFortyThree = stepFortyTwo.concat(SEED)
  const stepFortyFour = stepFortyThree.concat(SEED)
  const stepFortyFive = stepFortyFour.concat(SEED)
  const stepFortySix = stepFortyFive.concat(SEED)
  const stepFortySeven = stepFortySix.concat(SEED)
  const stepFortyEight = stepFortySeven.concat(SEED)
  const stepFortyNine = stepFortyEight.concat(SEED)
  const stepFifty = stepFortyNine.concat(SEED)
  const stepFiftyOne = stepFifty.concat(SEED)
  const stepFiftyTwo = stepFiftyOne.concat(SEED)
  const stepFiftyThree = stepFiftyTwo.concat(SEED)
  const stepFiftyFour = stepFiftyThree.concat(SEED)
  return stepFiftyFour
}
